import { useState } from "react";
import { toast } from "react-toastify";
import { useAuth } from "../context/AuthContext";

export default function AuthPage() {
  const { login, register } = useAuth();
  const [isLogin, setIsLogin] = useState(true);
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [loading, setLoading] = useState(false);

  async function handle() {
    if (!form.email || !form.password) {
      toast.error("Please fill all fields");
      return;
    }
    if (!isLogin && !form.name.trim()) {
      toast.error("Please enter your name");
      return;
    }
    setLoading(true);
    try {
      if (isLogin) await login(form.email, form.password);
      else await register(form.name.trim(), form.email, form.password);
      toast.success(
        isLogin ? "Welcome back! 👋" : "Account created! Let's learn! 🎉",
      );
    } catch (err) {
      toast.error(err.response?.data?.message || "Something went wrong");
    } finally {
      setLoading(false);
    }
  }

  const inp =
    "w-full px-4 py-3 rounded-xl border-2 border-slate-200 bg-slate-50 text-slate-800 text-sm focus:outline-none focus:border-blue-900 focus:bg-white transition-all duration-200 placeholder:text-slate-400 font-nunito";

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-blue-950 to-[#0f3460] flex items-center justify-center px-4">
      <div className="w-full max-w-md fade-in">
        {/* Logo */}
        <div className="text-center mb-8">
          <h1 className="font-playfair text-5xl text-white mb-2">SpeakUp</h1>
          <p className="text-blue-200 text-sm">
            🗣️ Your smart English learning companion
          </p>
        </div>

        <div className="bg-[#4d4b5d] rounded-3xl shadow-2xl p-8">
          <h2 className="text-2xl font-extrabold text-gray-200 mb-1">
            {isLogin ? "Welcome Back!" : "Create Account"}
          </h2>
          <p className="text-sm text-slate-400 mb-6">
            {isLogin
              ? "Continue your learning journey"
              : "Start your English journey today"}
          </p>

          <div className="space-y-3">
            {!isLogin && (
              <input
                className={inp}
                placeholder="Full Name"
                name="name"
                value={form.name}
                onChange={(e) =>
                  setForm((f) => ({ ...f, name: e.target.value }))
                }
              />
            )}
            <input
              className={inp}
              placeholder="Email Address"
              type="email"
              id="email"
              name="email"
              value={form.email}
              onChange={(e) =>
                setForm((f) => ({ ...f, email: e.target.value }))
              }
            />
            <input
              className={inp}
              placeholder="Password"
              type="password"
              value={form.password}
              onChange={(e) =>
                setForm((f) => ({ ...f, password: e.target.value }))
              }
              onKeyDown={(e) => e.key === "Enter" && handle()}
            />
          </div>

          <button
            onClick={handle}
            disabled={loading}
            className="mt-5 w-full bg-blue-900 hover:bg-blue-800 disabled:opacity-50 text-white font-bold py-3.5 rounded-xl text-sm transition-all duration-200 hover:-translate-y-0.5 active:translate-y-0"
          >
            {loading
              ? "Please wait..."
              : isLogin
                ? "Login →"
                : "Create Account →"}
          </button>

          <p className="text-xs text-slate-400 text-center mt-5">
            {isLogin ? "Don't have an account? " : "Already registered? "}
            <span
              className="text-blue-900 font-bold cursor-pointer hover:underline"
              onClick={() => {
                setIsLogin((l) => !l);
                setForm({ name: "", email: "", password: "" });
              }}
            >
              {isLogin ? "Sign up free" : "Login"}
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}
